// Get the first item from the Critic Request2 node
const raw = $('Critic Request2').first().json;

// Take the 'body' field
let bodyStr = raw.body || "";

// Clean the JSON string by filling missing numeric values with 0
// This handles cases like "alignmentScore": , "complianceScore": ,
bodyStr = bodyStr.replace(/:\s*,/g, ": 0,");

// Also handle a potential trailing comma before closing }
bodyStr = bodyStr.replace(/,\s*}/g, "}");

let body;

try {
    // Parse the cleaned JSON string
    body = JSON.parse(bodyStr);
} catch (e) {
    // Fallback if parsing still fails
    body = { rawBody: bodyStr };
}

// Return as n8n item
return [{ json: body }];

const request = $('Parse Request').first().json;
const aiResponse = $input.first().json;
let evaluation = { scores: { clarity: 5, persuasiveness: 5, specificity: 5, emotional_appeal: 5, funder_alignment: 5, overall: 5 }, issues: [], strengths: [], weaknesses: [] };
try {
  const responseText = aiResponse.message?.content || aiResponse.text || '';
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) evaluation = JSON.parse(jsonMatch[0]);
} catch (e) { evaluation.parseError = e.message; }
if (!evaluation.scores.overall) {
  const s = evaluation.scores;
  evaluation.scores.overall = Math.round(((s.clarity + s.persuasiveness + s.specificity + s.emotional_appeal + s.funder_alignment) / 5) * 10) / 10;
}
const issuesByType = {};
for (const issue of evaluation.issues || []) { const t = issue.type || 'OTHER'; if (!issuesByType[t]) issuesByType[t] = []; issuesByType[t].push(issue); }
const priorityIssues = (evaluation.issues || []).filter(i => ['PASSIVE_VOICE','JARGON','VAGUE_CLAIMS'].includes(i.type)).slice(0, 5);
return [{ json: { funderName: request.funderName, grantPurpose: request.grantPurpose, proposalText: request.proposalText, deadline: request.deadline, budget: request.budget, budgetAmount: request.budgetAmount, scores: evaluation.scores, issuesByType, issueCount: (evaluation.issues || []).length, strengths: evaluation.strengths || [], weaknesses: evaluation.weaknesses || [], priorityIssues, needsRewrite: evaluation.scores.overall < 7 } }];

